// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX 1000001

// Structure to represent a graph
typedef struct {
    int *adj;
    int *visited;
    int *museums;
    int n;
} Graph;

// Function to create a graph
Graph* createGraph(int n) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->adj = (int*) malloc(n * sizeof(int));
    graph->visited = (int*) malloc(n * sizeof(int));
    graph->museums = (int*) malloc(n * sizeof(int));
    graph->n = n;
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int u, int v) {
    graph->adj[u] = v;
}

// Function to perform DFS
void dfs(Graph* graph, int u, int* visited, int* museums, int* total) {
    visited[u] = 1;
    *total += museums[u];
    if (graph->adj[u] != -1 && !visited[graph->adj[u]]) {
        dfs(graph, graph->adj[u], visited, museums, total);
    }
}

// Function to calculate the total number of museums
int calculateMuseums(Graph* graph, int k) {
    int* visited = (int*) malloc(graph->n * sizeof(int));
    int* museums = graph->museums;
    int total = 0;
    int months = k;
    for (int i = 0; i < graph->n; i++) {
        if (!visited[i]) {
            if (months > 0) {
                int temp = 0;
                dfs(graph, i, visited, museums, &temp);
                total += temp;
                months--;
            } else {
                break;
            }
        }
    }
    if (months > 0) {
        return -1;
    }
    return total;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m, k;
        scanf("%d %d %d", &n, &m, &k);
        Graph* graph = createGraph(n);
        for (int i = 0; i < n; i++) {
            graph->adj[i] = -1;
            graph->visited[i] = 0;
        }
        for (int i = 0; i < m; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            addEdge(graph, u - 1, v - 1);
        }
        for (int i = 0; i < n; i++) {
            scanf("%d", &graph->museums[i]);
        }
        printf("%d\n", calculateMuseums(graph, k));
    }
    return 0;
}

