#include <iostream>
#include <vector>
using namespace std;

// Structure to represent a graph
struct Graph {
    vector<vector<int>> adj;
    vector<int> visited;
    vector<int> museums;
    int n;
};

// Function to create a graph
Graph createGraph(int n) {
    Graph graph;
    graph.adj.resize(n);
    graph.visited.resize(n, 0);
    graph.museums.resize(n);
    graph.n = n;
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph& graph, int u, int v) {
    graph.adj[u].push_back(v);
}

// Function to perform DFS
void dfs(Graph& graph, int u, int& total) {
    graph.visited[u] = 1;
    total += graph.museums[u];
    for (int v : graph.adj[u]) {
        if (!graph.visited[v]) {
            dfs(graph, v, total);
        }
    }
}

// Function to calculate the total number of museums
int calculateMuseums(Graph& graph, int k) {
    int total = 0;
    int months = k;
    for (int i = 0; i < graph.n; i++) {
        if (!graph.visited[i]) {
            if (months > 0) {
                int temp = 0;
                dfs(graph, i, temp);
                total += temp;
                months--;
            } else {
                break;
            }
        }
    }
    if (months > 0) {
        return -1;
    }
    return total;
}

int main() {
    int t;
    cin >> t;
    while (t--) {
        int n, m, k;
        cin >> n >> m >> k;
        Graph graph = createGraph(n);
        for (int i = 0; i < m; i++) {
            int u, v;
            cin >> u >> v;
            addEdge(graph, u - 1, v - 1);
        }
        for (int i = 0; i < n; i++) {
            cin >> graph.museums[i];
        }
        cout << calculateMuseums(graph, k) << endl;
    }
    return 0;
}

