public class Main {
    static class Graph {
        ArrayList<ArrayList<Integer>> adj;
        int[] visited;
        int[] museums;
        int n;

        public Graph(int n) {
            adj = new ArrayList<>();
            for (int i = 0; i < n; i++) {
                adj.add(new ArrayList<>());
            }
            visited = new int[n];
            museums = new int[n];
            this.n = n;
        }
    }

    public static void addEdge(Graph graph, int u, int v) {
        graph.adj.get(u).add(v);
    }

    public static void dfs(Graph graph, int u, int[] total) {
        graph.visited[u] = 1;
        total[0] += graph.museums[u];
        for (int v : graph.adj.get(u)) {
            if (graph.visited[v] == 0) {
                dfs(graph, v, total);
            }
        }
    }

    public static int calculateMuseums(Graph graph, int k) {
        int total = 0;
        int months = k;
        for (int i = 0; i < graph.n; i++) {
            if (graph.visited[i] == 0) {
                if (months > 0) {
                    int[] temp = new int[1];
                    dfs(graph, i, temp);
                    total += temp[0];
                    months--;
                } else {
                    break;
                }
            }
        }
        if (months > 0) {
            return -1;
        }
        return total;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            int m = scanner.nextInt();
            int k = scanner.nextInt();
            Graph graph = new Graph(n);
            for (int i = 0; i < m; i++) {
                int u = scanner.nextInt() - 1;
                int v = scanner.nextInt() - 1;
                addEdge(graph, u, v);
            }
            for (int i = 0; i < n; i++) {
                graph.museums[i] = scanner.nextInt();
            }
            System.out.println(calculateMuseums(graph, k));
        }
    }
}

